+                salt2: wal.header().salts.salt2.wrapping_add(1),
+            };
+            let truncate = matches!(post_action, CheckpointPostAction::TruncateWal);
+            wal.reset(cx, new_seq, new_salts, truncate)?;
+            info!(
+                new_checkpoint_seq = new_seq,
+                action = ?post_action,
+                "WAL reset after checkpoint"
+            );
+            Ok(true)
+        }
